def digit_sum(n):
    total = 0
    for ch in str(n):
        total += int(ch)
    return total

def unique_items(items):
    seen = set()
    out = []
    for item in items:
        if item not in seen:
            seen.add(item)
            out.append(item)
    return out

def clamp(x, lo, hi):
    if x < lo:
        return lo
    if x > hi:
        return hi
    return x
